// ── HELPERS ───────────────────────────────────────────────────────────────────
function dateKey(d) {
  return `${d.getFullYear()}-${String(d.getMonth()+1).padStart(2,'0')}-${String(d.getDate()).padStart(2,'0')}`;
}
function fromKey(k) { return new Date(k + 'T12:00:00'); }
function formatWeekday(d) { return d.toLocaleDateString('en-US',{weekday:'long'}); }
function formatDay(d) { return d.getDate(); }
function formatMonthYear(d) { return d.toLocaleDateString('en-US',{month:'long',year:'numeric'}); }
function formatFullDate(d) { return d.toLocaleDateString('en-US',{weekday:'long',month:'long',day:'numeric',year:'numeric'}); }

function buildCalGrid(year, month) {
  const firstDay = new Date(year, month, 1).getDay();
  const daysInMonth = new Date(year, month+1, 0).getDate();
  const prevDays = new Date(year, month, 0).getDate();
  const cells = [];
  for (let i = firstDay-1; i >= 0; i--) cells.push({day:prevDays-i,current:false,month:month-1,year:month===0?year-1:year});
  for (let d = 1; d <= daysInMonth; d++) cells.push({day:d,current:true,month,year});
  const rem = 42 - cells.length;
  for (let d = 1; d <= rem; d++) cells.push({day:d,current:false,month:month+1,year:month===11?year+1:year});
  return cells;
}

// ── STATIC DATA LOADING ───────────────────────────────────────────────────────
async function loadIndex() {
  try {
    const res = await fetch('/data/index.json?t=' + Date.now());
    if (!res.ok) return { dates: [] };
    return res.json();
  } catch(e) { return { dates: [] }; }
}

async function loadDayData(key) {
  const res = await fetch(`/data/${key}.json`);
  if (!res.ok) throw new Error(`No static data for ${key}`);
  return res.json();
}

// ── LIVE API CALLS (fallback for dates without static files) ──────────────────
async function fetchLiveArticles(dateStr) {
  const readable = fromKey(dateStr).toLocaleDateString('en-US',{month:'long',day:'numeric',year:'numeric'});
  const prompt = `Search for Buffalo Bills NFL news articles published on ${readable}.
Return a JSON object:
{"themes":["theme 1","theme 2"],"writeup":"3-5 sentence narrative summary","articles":[{"title":"...","source":"...","url":"..."}]}
Rules: themes 2-4 short phrases, writeup engaging sports journalism, articles 3-8 real URLs.
If none found: themes:["Quiet news day"], writeup:"No significant Bills news found.", articles:[{"title":"No coverage found","source":"—","url":""}]
Your response must be only valid JSON starting with { and ending with }. No markdown, no backticks, no preamble.`;

  const res = await fetch('https://api.anthropic.com/v1/messages', {
    method:'POST', headers:{'Content-Type':'application/json'},
    body: JSON.stringify({
      model:'claude-sonnet-4-6', max_tokens:1500,
      tools:[{type:'web_search_20250305',name:'web_search'}],
      messages:[{role:'user',content:prompt}]
    })
  });
  const data = await res.json();
  if (!res.ok) throw new Error(data.error?.message||'API error');
  const tb = data.content?.find(b=>b.type==='text');
  if (!tb) throw new Error('No text in response');
  const jsonMatch = tb.text.match(/\{[\s\S]*\}/);
  if (!jsonMatch) throw new Error('No JSON in response');
  return JSON.parse(jsonMatch[0]);
}

async function fetchLiveSearchResults(query) {
  const prompt = `Search for Buffalo Bills NFL news and history related to: "${query}"
Return ONLY this JSON:
{"results":[{"date":"YYYY-MM-DD","relevance":"One sentence why relevant","articles":[{"title":"...","source":"...","url":"..."}]}]}
3-8 most relevant dates, newest first. Only real URLs. Respond ONLY with raw JSON.`;
  const res = await fetch('https://api.anthropic.com/v1/messages', {
    method:'POST', headers:{'Content-Type':'application/json'},
    body: JSON.stringify({model:'claude-sonnet-4-6',max_tokens:2000,
      tools:[{type:'web_search_20250305',name:'web_search'}],
      messages:[{role:'user',content:prompt}]})
  });
  const data = await res.json();
  if (!res.ok) throw new Error(data.error?.message||'API error');
  const tb = data.content?.find(b=>b.type==='text');
  if (!tb) throw new Error('No text in response');
  const jsonMatch = tb.text.match(/\{[\s\S]*\}/);
  if (!jsonMatch) throw new Error('No JSON in response');
  return JSON.parse(jsonMatch[0]);
}

async function fetchThemedPage(type) {
  const prompts = {
    creators: `Search for Buffalo Bills content creators, YouTubers, podcasters, bloggers, and social media personalities who cover the Bills. Return JSON:
{"creators":[{"name":"Creator or Channel Name","platform":"YouTube / Podcast / Twitter / Blog","handle":"@handle or URL","bio":"2-3 sentence description","url":"https://..."}]}
Include 8-14 creators. Only real, active creators. Respond ONLY with raw JSON.`
  };
  const res = await fetch('https://api.anthropic.com/v1/messages', {
    method:'POST', headers:{'Content-Type':'application/json'},
    body: JSON.stringify({model:'claude-sonnet-4-6',max_tokens:2000,
      tools:[{type:'web_search_20250305',name:'web_search'}],
      messages:[{role:'user',content:prompts[type]}]})
  });
  const data = await res.json();
  if (!res.ok) throw new Error(data.error?.message||'API error');
  const tb = data.content?.find(b=>b.type==='text');
  if (!tb) throw new Error('No text in response');
  const jsonMatch = tb.text.match(/\{[\s\S]*\}/);
  if (!jsonMatch) throw new Error('No JSON in response');
  return JSON.parse(jsonMatch[0]);
}

