// ── HOMEPAGE ──────────────────────────────────────────────────────────────────
const DOW = ['Su','Mo','Tu','We','Th','Fr','Sa'];

function HomePage({onDaySelect}) {
  const today = new Date(); today.setHours(12,0,0,0);
  const PAGE_SIZE = 14;
  const [index, setIndex] = useState({dates:[]});
  const [cache, setCache] = useState({});
  const [calOpen, setCalOpen] = useState(false);
  const [calYear, setCalYear] = useState(today.getFullYear());
  const [calMonth, setCalMonth] = useState(today.getMonth());
  const [pickedKey, setPickedKey] = useState(null);
  const [page, setPage] = useState(0);
  const pickedRowRef = useRef(null);

  useEffect(()=>{
    loadIndex().then(idx=>{
      setIndex(idx);
      (idx.dates||[]).slice(0, PAGE_SIZE).forEach(async key=>{
        try {
          const data = await loadDayData(key);
          setCache(c=>({...c,[key]:data}));
        } catch(e){}
      });
    });
  },[]);

  // When page changes, load that page's dates
  useEffect(()=>{
    const allDates = index.dates || [];
    const start = page * PAGE_SIZE;
    allDates.slice(start, start + PAGE_SIZE).forEach(async key=>{
      if (cache[key]) return;
      try {
        const data = await loadDayData(key);
        setCache(c=>({...c,[key]:data}));
      } catch(e){}
    });
  },[page, index]);

  const allDates = index.dates || [];
  const totalPages = Math.ceil(allDates.length / PAGE_SIZE);
  const pageDates = allDates.slice(page * PAGE_SIZE, (page + 1) * PAGE_SIZE).map(fromKey);

  const listDates = (()=>{
    if (pickedKey && !allDates.includes(pickedKey)) return [fromKey(pickedKey), ...pageDates];
    return pageDates;
  })();

  async function pickDate(key) {
    setPickedKey(key);
    setCalOpen(false);
    if (!cache[key]) {
      try {
        const data = await loadDayData(key);
        setCache(c=>({...c,[key]:data}));
      } catch(e) {}
    }
    setTimeout(()=>pickedRowRef.current?.scrollIntoView({behavior:'smooth',block:'center'}),80);
  }

  function handleCalPick(cell) {
    const d = new Date(cell.year,cell.month,cell.day,12,0,0);
    if(d>today) return;
    pickDate(dateKey(d));
    setCalYear(cell.year); setCalMonth(cell.month);
  }

  function prevMonth(){if(calMonth===0){setCalYear(y=>y-1);setCalMonth(11);}else setCalMonth(m=>m-1);}
  function nextMonth(){const nd=new Date(calYear,calMonth+1,1);if(nd>today)return;if(calMonth===11){setCalYear(y=>y+1);setCalMonth(0);}else setCalMonth(m=>m+1);}

  const cells = buildCalGrid(calYear,calMonth);
  const todayKey = dateKey(today);
  const calMonthLabel = new Date(calYear,calMonth,1).toLocaleDateString('en-US',{month:'long',year:'numeric'});
  const nextMonthFuture = new Date(calYear,calMonth+1,1)>today;
  const availableKeys = new Set(index.dates||[]);

  return (
    <main className="container">


      {pickedKey && !(index.dates||[]).includes(pickedKey) && (
        <div className="spotlight-banner">
          📅 Showing results for <strong>{formatFullDate(fromKey(pickedKey))}</strong>
          <button className="spotlight-close" onClick={()=>setPickedKey(null)}>✕</button>
        </div>
      )}

      <div className="section-label">
        {pickedKey && !(index.dates||[]).includes(pickedKey) ? 'Selected Date + Recent Coverage' : 'Recent Coverage'}
      </div>
      <div className="divider-line" />

      {listDates.map((date,i)=>{
        const key=dateKey(date);
        const data=cache[key];
        const isPicked=key===pickedKey;
        const chips=data?.themes?data.themes:['Click to view'];
        return (
          <div key={key} className="day-entry" style={{animationDelay:`${i*28}ms`}} ref={isPicked?pickedRowRef:null}>
            <div className={`day-row${isPicked?' highlighted':''}`} onClick={()=>onDaySelect(key)}>
              <img
                className="day-thumb"
                src={data?.imageUrl || FALLBACK_IMAGE}
                alt="Bills news"
                onError={e=>{e.target.src=FALLBACK_IMAGE;}}
              />
              <div className="day-label">
                <div className="day-weekday">{formatWeekday(date)}</div>
                <div className="day-date">{formatDay(date)}</div>
                <div className="day-month">{formatMonthYear(date)}</div>
              </div>
              <div className="theme-chips">
                {chips.map((chip,ci)=>(
                  <span key={ci} className={`chip${!data?' unloaded':''}`}>{chip}</span>
                ))}
              </div>
              <div style={{color:BLUE,paddingTop:6,fontSize:18}}>›</div>
            </div>
          </div>
        );
      })}

      {totalPages > 1 && (
        <div className="pagination">
          <button className="page-btn" onClick={()=>{ setPage(p=>p-1); window.scrollTo(0,0); }} disabled={page===0}>
            ← Newer
          </button>
          <span className="page-info">Page {page + 1} of {totalPages}</span>
          <button className="page-btn" onClick={()=>{ setPage(p=>p+1); window.scrollTo(0,0); }} disabled={page>=totalPages-1}>
            Older →
          </button>
        </div>
      )}
    </main>
  );
}

