function DayDetailPage({dayKey, onBack}) {
  const date = fromKey(dayKey);
  const [data, setData] = useState(null);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState(null);

  async function load() {
    setLoading(true); setError(null);
    try {
      try {
        const d = await loadDayData(dayKey);
        setData(d);
      } catch(e) {
        const d = await fetchLiveArticles(dayKey);
        setData(d);
      }
    } catch(e) { setError(e.message); }
    finally { setLoading(false); }
  }

  useEffect(()=>{ load(); },[dayKey]);

  return (
    <main className="container">
      <button className="detail-back" onClick={onBack}>← Back to Archive</button>
      <div className="detail-hero">
        <div className="detail-weekday">{formatWeekday(date)}</div>
        <div className="detail-date-big">{date.toLocaleDateString('en-US',{month:'long',day:'numeric'})}</div>
        <div className="detail-year">{date.getFullYear()}</div>
      </div>
      {loading && <div className="detail-loading"><div className="spinner"/>Searching Bills archive for {formatFullDate(date)}…</div>}
      {error && <div><div className="detail-error">Failed to load: {error}</div><button className="detail-refresh" onClick={load}>↻ Retry</button></div>}
      {data && !loading && (
        <>
          <div className="detail-image-wrap">
            <img className="detail-image"
              src={data.imageUrl || FALLBACK_IMAGE}
              alt="Bills news"
              onError={e=>{e.target.src=FALLBACK_IMAGE;}}
            />
          </div>
          {data.writeup && <p className="detail-writeup">{data.writeup}</p>}
          {data.articles && data.articles.length>0 && data.articles[0].title!=='No coverage found' && (
            <div className="articles-label">Coverage from this day</div>
          )}
          <ul className="article-list">
            {(data.articles||[]).map((a,ai)=>(
              <li key={ai} className="article-item">
                <div className="article-bullet"/>
                {a.url
                  ?<a className="article-link" href={a.url} target="_blank" rel="noopener noreferrer">{a.title}</a>
                  :<span className="article-link" style={{cursor:'default',color:'#6b7280'}}>{a.title}</span>}
                <span className="article-source">{a.source}</span>
              </li>
            ))}
          </ul>
          <button className="detail-refresh" onClick={load} style={{marginTop:16}}>↻ Refresh from web</button>
        </>
      )}
    </main>
  );
}

// ── SEARCH PAGE ───────────────────────────────────────────────────────────────
function highlight(text, query) {
  if (!query) return text;
  const parts = text.split(new RegExp(`(${query.replace(/[.*+?^${}()|[\]\\]/g,'\\$&')})`, 'gi'));
  return parts.map((p,i)=>p.toLowerCase()===query.toLowerCase()?<mark key={i} className="search-match">{p}</mark>:p);
}

function SearchPage({query, onDaySelect, onBack}) {
  const [results, setResults] = useState(null);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState(null);
  async function load() {
    setLoading(true); setError(null);
    try { const data=await fetchLiveSearchResults(query); setResults(data.results||[]); }
    catch(e) { setError(e.message); }
    finally { setLoading(false); }
  }
  useEffect(()=>{load();},[query]);
  return (
    <main className="container">
      <button className="detail-back" onClick={onBack}>← Back to Archive</button>
      <div className="search-results-header">
        <div className="search-results-title">Search: <span>"{query}"</span></div>
        {!loading&&results&&<div className="search-results-meta">{results.length} date{results.length!==1?'s':''} found</div>}
      </div>
      <div className="divider-line"/>
      {loading&&<div className="search-loading"><div className="spinner"/>Searching Bills history for "{query}"…</div>}
      {error&&<div><div className="detail-error">Search failed: {error}</div><button className="detail-refresh" onClick={load}>↻ Retry</button></div>}
      {results&&!loading&&results.length===0&&<div className="search-none">No results found for "{query}".</div>}
      {results&&!loading&&results.map((r,ri)=>{
        const date=fromKey(r.date);
        return (
          <div key={ri} className="day-entry" style={{animationDelay:`${ri*40}ms`}}>
            <div className="search-result-row" onClick={()=>onDaySelect(r.date)}>
              <div className="day-label">
                <div className="day-weekday">{formatWeekday(date)}</div>
                <div className="day-date">{formatDay(date)}</div>
                <div className="day-month">{formatMonthYear(date)}</div>
              </div>
              <div>
                <div style={{fontSize:13,color:'#1f2937',marginBottom:8,fontStyle:'italic',lineHeight:1.5}}>{highlight(r.relevance,query)}</div>
                <div className="theme-chips">
                  {(r.articles||[]).slice(0,3).map((a,ai)=>(
                    <span key={ai} className="chip" onClick={e=>{e.stopPropagation();if(a.url)window.open(a.url,'_blank');}}>
                      {a.title.length>60?a.title.slice(0,57)+'…':a.title}
                    </span>
                  ))}
                </div>
              </div>
              <div style={{color:BLUE,paddingTop:6,fontSize:18}}>›</div>
            </div>
          </div>
        );
      })}
    </main>
  );
}

